const MAX_LEN: i64 = 3000;

fn solve(s: String, k: i64) -> String {
    let s_bytes = s.as_bytes();
    let s_len = s_bytes.len();
    if s_len == 0 {
        if k == 0 {
            return ".".to_string();
        }
        return ".".to_string();
    }

    let mut lengths = Vec::with_capacity(s_len);
    let mut current_length: i64 = 0;

    for i in 0..s_len {
        let c = s_bytes[i];
        current_length = match c {
            b'*' => if current_length > 0 { current_length - 1 } else { 0 },
            b'#' => std::cmp::min(current_length * 2, MAX_LEN),
            b'%' => current_length,
            _ => {
                if current_length >= MAX_LEN {
                    current_length
                } else {
                    current_length + 1
                }
            }
        };
        lengths.push(current_length);
    }

    let total_length = *lengths.last().unwrap_or(&0);
    if k >= total_length {
        return ".".to_string();
    }

    let mut cur_k = k;
    for i in (0..s_len).rev() {
        let c = s_bytes[i];
        let prev_len = if i == 0 { 0 } else { *lengths.get(i-1).unwrap_or(&0) };

        match c {
            b'*' => {},
            b'#' => {
                let half = prev_len;
                if half == 0 {
                    continue;
                }
                if cur_k >= half {
                    cur_k = cur_k - half;
                }
            },
            b'%' => {
                if prev_len > 0 {
                    cur_k = prev_len - 1 - cur_k;
                }
            },
            _ => {
                if cur_k == prev_len {
                    return String::from_utf8(vec![c]).unwrap();
                }
            }
        }
    }

    ".".to_string()
}
```

### Explanation
1. **Precompute Lengths**:
   - Iterate through `s` to compute the result length after each operation. Cap lengths at `MAX_LEN` (3000) to avoid overflow and excessive computation.

2. **Check Bounds**:
   - If `k` exceeds the final result length, return `'.'`.

3. **Backward Processing**:
   - Process `s` in reverse to adjust `k` for each operation:
     - **'*'** (delete): No change to `k` since the deleted character doesn't affect positions before the deletion.
     - **'#'** (duplicate): Adjust `k` to the corresponding position in the original string (either first or second half).
     - **'%'** (reverse): Reverse the position using `prev_len - 1 - k`.
     - **Letter**: If `k` corresponds to the last position (after the letter was appended), return the letter.
   - If `k` is successfully mapped to a letter during backward processing, return it; otherwise, return `'.'`.

This approach efficiently navigates the operations in reverse, leveraging precomputed lengths to avoid constructing large intermediate strings, ensuring optimal performance even for large inputs.
